import React from 'react';
import { Link } from 'react-router-dom';

// No necesitamos SocialLinks.jsx como archivo separado, lo integramos aquí.
const SocialIcons = () => {
    return (
        <div className="flex justify-center gap-3 text-neutral-700 dark:text-neutral-300"> {/* Ajustado gap para compactar */}
            {/* Asegúrate de que estos archivos PNG existan en public/media/icons/ */}
            {/* Si no tienes estas imágenes, los íconos no se mostrarán. */}
            <a href="https://www.facebook.com/TuPaginaDeFacebook" target="_blank" rel="noopener noreferrer" className="opacity-80 hover:opacity-100 hover:scale-110 transition-all duration-200">
                <img src="/media/icons/facebook_icon.png" alt="Facebook" className="w-5 h-5" /> {/* Tamaños más pequeños */}
            </a>
            <a href="https://www.instagram.com/TuCuentaDeInstagram" target="_blank" rel="noopener noreferrer" className="opacity-80 hover:opacity-100 hover:scale-110 transition-all duration-200">
                <img src="/media/icons/instagram_icon.png" alt="Instagram" className="w-5 h-5" /> {/* Tamaños más pequeños */}
            </a>
            <a href="https://www.tiktok.com/@TuCuentaDeTikTok" target="_blank" rel="noopener noreferrer" className="opacity-80 hover:opacity-100 hover:scale-110 transition-all duration-200">
                <img src="/media/icons/tiktok_icon.png" alt="TikTok" className="w-5 h-5" /> {/* Tamaños más pequeños */}
            </a>
        </div>
    );
};

function Footer() {
    const currentYear = new Date().getFullYear();

    return (
        <footer className="bg-yellow-50 dark:bg-neutral-800 text-neutral-700 dark:text-neutral-200 py-3 mt-auto shadow-inner transition-colors duration-300 font-sans"> {/* Reducido py para compactar */}
            <div className="max-w-xl mx-auto px-4 text-sm font-medium tracking-wide"> {/* max-w-xl para un footer más estrecho */}

                {/* Copyright */}
                <p className="text-neutral-700 dark:text-neutral-300 text-center mb-4 leading-snug text-xs"> {/* Reducido mb y text-xs */}
                    © {currentYear} Repositorio Bicentenario de Bolivia. Todos los derechos reservados.
                    {/* Eliminado "Trinity Team" */}
                </p>

                <div className="flex flex-col sm:flex-row justify-center items-start sm:items-center gap-10 sm:gap-20 mb-4"> {/* Ajustado gap y flexbox para el layout */}

                    {/* Columna Izquierda: Navegación */}
                    <div className="text-center"> {/* Alineación central */}
                        <h3 className="text-neutral-800 dark:text-neutral-100 font-semibold mb-2 text-sm uppercase"> {/* Reducido mb y text-sm */}
                            Navegación
                        </h3>
                        <ul className="space-y-1 text-xs"> {/* Reducido space-y y text-xs */}
                            <li><Link to="/acerca-de" className="text-neutral-600 dark:text-neutral-300 hover:text-yellow-600 dark:hover:text-yellow-400 transition">Acerca de</Link></li>
                            <li><Link to="/mas-de-nosotros" className="text-neutral-600 dark:text-neutral-300 hover:text-yellow-600 dark:hover:text-yellow-400 transition">Más de Nosotros</Link></li>
                            <li><Link to="/contacto" className="text-neutral-600 dark:text-neutral-300 hover:text-yellow-600 dark:hover:text-yellow-400 transition">Contacto</Link></li>
                        </ul>
                    </div>

                    {/* Columna Derecha: Solo Íconos de Redes Sociales */}
                    <div className="flex flex-col items-center justify-center pt-2"> {/* pt-2 para alinear con la lista de navegación */}
                        <SocialIcons /> {/* Componente de íconos integrado */}
                    </div>

                    {/* Eliminada la sección "Sobre el Repositorio" */}

                </div>

                {/* Línea divisoria */}
                <div className="w-3/4 mx-auto border-t border-neutral-300 dark:border-neutral-600 my-3"></div> {/* Reducido my */}

                {/* Cita final */}
                <p className="text-center text-xs text-neutral-500 dark:text-neutral-500 tracking-wide italic mb-1"> {/* Reducido mb */}
                    “Conocer nuestra historia es entender nuestro presente.”
                </p>

                {/* Crédito de Alberto Navarro */}
                <p className="text-center text-xs text-neutral-500 dark:text-neutral-500 tracking-wide"> {/* Mismo tamaño de fuente */}
                    Titulizado por Alberto Navarro
                </p>
            </div>
        </footer>
    );
}

export default Footer;
